THE CLAIM:
{
 "title": "Market ceiling may be too low; plan sized for wrong market",
 "narrative": "The model caps the market base at €360M, cut down from €495M using a 10–12% growth rate. But that growth rate comes from a €8.5–9.5B report covering a far broader category than rack PDUs, so the fix imported the same error it claimed to remove. Germany alone is forecast at $509.6M by 2031, already above the whole base. If the true base sits at €400M or more, the Year-1 plan is sized for the wrong market.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "The growth rate used to cut the ceiling came from a broad multi-category report, not rack PDUs.",
   "refs": [
    "digest:tam-base#c4",
    "ledger:tamBase"
   ]
  },
  {
   "step": "propagation",
   "text": "Germany alone reaches $509.6M by 2031 and global anchors span $1.7B to $3.94B.",
   "refs": [
    "digest:tam-base#c9",
    "digest:tam-global-crosscheck#c4",
    "digest:tam-global-crosscheck#c9"
   ]
  },
  {
   "step": "model-impact",
   "text": "A low base sizes the Year-1 plan too small for certification and channel needs.",
   "refs": [
    "ledger:tamBase",
    "ledger:serviceableFactor",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "falsifier": "A dedicated rack-PDU report showing the EU base at or below €360M for 2025/2026.",
 "category": "fact",
 "evidence": [
  {
   "title": "European Union Power and Cable Management - Market Analysis, Forecast, Size, Trends and Insights",
   "sourceType": "industry-report",
   "publisher": "IndexBox",
   "date": "2026-04-28",
   "excerpt": "The European Union Power And Cable Management market is estimated at €8.5–€9.5 billion in 2026... Managed and intelligent power distribution units (PDUs) represent the fastest-growing segment, expanding at 10–12% annually",
   "url": "https://www.indexbox.io/store/european-union-power-and-cable-management-market-analysis-forecast-size-trends-and-insights/",
   "attached": true
  },
  {
   "title": "Data Center Rack Power Distribution Unit (PDU) Market Size & Share Analysis",
   "sourceType": "industry-report",
   "publisher": "Mordor Intelligence",
   "date": "2019-05-07",
   "excerpt": "the data center rack power distribution unit (PDU) market size is expected to increase from USD 2.78 billion in 2025 to USD 3.01 billion in 2026 and reach USD 4.62 billion by 2031, growing at a CAGR of 8.96%",
   "url": "https://www.mordorintelligence.com/industry-reports/data-center-rack-pdu-market",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "tamBase",
  "label": "Central Europe rack-PDU market, all segments/buyers",
  "kind": "estimated",
  "value": 300,
  "unit": "EUR_M",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 240,
   "high": 360
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down scope-down from the global rack-PDU base",
   "expression": "Global rack-PDU $2.81B (Grand View, 2025) × Europe ≈ 30% [est.; NA = 38% per same source] ≈ $843M ≈ €775M @0.92 (Jul 2026) × CE-7 = 39.8% of Europe colo MW (Statista 2025) ≈ €310M → curated €300M",
   "crossCheck": "Refinement cycle 1: the prior €495M ceiling (BIS/R&M €2.45B) measures PDUs+PSUs combined — a broader category growing 21% CAGR vs intelligent-PDU 10–12% (IndexBox). Contaminated ceiling removed; band top lowered to €360M."
  },
  "provenance": {
   "rationale": "No public Europe- or CE-scoped rack-PDU figure exists; the scope-down chain anchors the value, and refinement cycle 1 killed the inflated PDUs+PSUs cross-check ceiling.",
   "promotionPath": "Commission the IndexBox EU Rack PDUs report (country tables) to pin the EU base directly."
  },
  "evidence": [
   {
    "title": "Data Center Rack PDU Market Size | Industry Report, 2033",
    "sourceType": "industry-report",
    "publisher": "Grand View Research",
    "date": "2025",
    "excerpt": "The global data center rack power distribution unit market size was estimated at USD 2.81 billion in 2025 and is projected to reach USD 5.87 billion by 2033... North America held 38.0% revenue share.",
    "attached": true
   },
   {
    "title": "Europe Data Center PDUs and PSUs Market 2025–2035",
    "sourceType": "industry-report",
    "publisher": "Research and Markets / BIS Research",
    "date": "2025",
    "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20.05 billion by 2035 from $2.45 billion in 2024 — a broader category (PDUs + PSUs) used as the cross-check ceiling.",
    "attached": true
   },
   {
    "title": "IndexBox — Rack PDUs Market in the European Union (country tables)",
    "sourceType": "pending",
    "publisher": "IndexBox",
    "date": null,
    "excerpt": "The directly-scoped EU rack-PDU report exists but its headline figure is paywalled — commissioning it would collapse the ±40% band.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
